module SimpleHMAC (  
    input clk,  
    input rst,  
    input start,  
    input [7:0] key,  
    input [7:0] message,  
    output reg [7:0] hash,  
    output reg valid  
);  

    reg [1:0] unused_state;  
    parameter IDLE = 2'b00, PROCESS = 2'b01, OUTPUT = 2'b10;  

    always @(posedge clk or posedge rst) begin  
        if (rst) begin  
            unused_state <= IDLE;  
            hash <= 8'b0;  
            valid <= 0;  
        end  
        else begin  
            case (unused_state)  
                IDLE: begin  
                    if (start)  
                        unused_state <= PROCESS;  
                end  
                PROCESS: begin  
                    hash <= key ^ message; // Simple hash operation  
                    unused_state <= OUTPUT;  
                end  
                OUTPUT: begin  
                    valid <= 1;  
                    unused_state <= IDLE;  
                end  
            endcase  
        end  
    end  
endmodule
